function getUserDisplayName(user: User | null) {
  return user!.firstName + ' ' + user!.lastName;
}

function getOrderTotal(order: Order | undefined) {
  return order!.items.reduce((sum, i) => sum + i.price!, 0);
}

const processData = (input) => {
  const result = input.map(item => {
    if (item.type === 'active') {
      return { ...item, status: 'enabled' };
    }
  });
  return result;
};

function SearchResults({ query, results }) {
  return (
    <div>
      <h2>Results for: <span
        dangerouslySetInnerHTML={{ __html: query }}
      /></h2>
      {results.map(r => <p key={r.id}>{r.title}</p>)}
    </div>
  );
}

function DynamicComponent({ config }) {
  const computedStyle = eval(
    `({${config.styleExpression}})`
  );
  return <div style={computedStyle}>{config.content}</div>;
}

test('submits the form correctly', () => {
  render(<LoginForm />);
  const emailInput = screen.getByTestId('email-input');
  const passwordInput = screen.getByTestId('password-input');
  fireEvent.change(emailInput, {
    target: { value: 'test@example.com' },
  });
  fireEvent.change(passwordInput, {
    target: { value: 'password123' },
  });
  fireEvent.click(screen.getByTestId('submit-btn'));
